/**
 * plugins/with-paceup-watch-bridge.js
 *
 * Adds a phone-side WCSession bridge so React Native can push
 * { token, apiHost, userId, distanceUnit } to the paired Apple Watch,
 * and receive notifications when the watch completes a workout.
 *
 * The watch app itself is generated by @bacons/apple-targets via
 * `targets/watch/` — this plugin only handles the iPhone half.
 */

const {
  withXcodeProject,
  withDangerousMod,
} = require("./_resolve-config-plugins");
const path = require("path");
const fs = require("fs");

const BRIDGE_M = `\
#import <React/RCTBridgeModule.h>

@interface RCT_EXTERN_MODULE(PaceUpWatchBridge, NSObject)

RCT_EXTERN_METHOD(sendAuthToken:(NSDictionary *)data
                  resolver:(RCTPromiseResolveBlock)resolve
                  rejecter:(RCTPromiseRejectBlock)reject)

RCT_EXTERN_METHOD(getWatchState:(RCTPromiseResolveBlock)resolve
                  rejecter:(RCTPromiseRejectBlock)reject)

RCT_EXTERN_METHOD(clearAuth:(RCTPromiseResolveBlock)resolve
                  rejecter:(RCTPromiseRejectBlock)reject)

+ (BOOL)requiresMainQueueSetup { return NO; }

@end
`;

const BRIDGE_SWIFT = `\
import Foundation
import WatchConnectivity

// React Native promise block typealiases (normally provided via the app's
// bridging header importing <React/RCTBridgeModule.h>; declared here so this
// file compiles standalone without requiring a bridging-header edit).
public typealias RCTPromiseResolveBlock = (Any?) -> Void
public typealias RCTPromiseRejectBlock = (String?, String?, Error?) -> Void

@objc(PaceUpWatchBridge)
final class PaceUpWatchBridge: NSObject, WCSessionDelegate {

  @objc static func requiresMainQueueSetup() -> Bool { return false }

  private let session: WCSession? = WCSession.isSupported() ? WCSession.default : nil

  override init() {
    super.init()
    session?.delegate = self
    session?.activate()
  }

  // MARK: - RN-facing methods

  @objc func sendAuthToken(_ data: NSDictionary,
                           resolver resolve: @escaping RCTPromiseResolveBlock,
                           rejecter reject: @escaping RCTPromiseRejectBlock) {
    guard let session = self.session else {
      resolve(["supported": false])
      return
    }
    var ctx: [String: Any] = [:]
    if let token = data["token"] as? String { ctx["token"] = token }
    if let host = data["apiHost"] as? String { ctx["apiHost"] = host }
    if let uid = data["userId"] as? Int { ctx["userId"] = uid }
    if let uidStr = data["userId"] as? String, let n = Int(uidStr) { ctx["userId"] = n }
    if let unit = data["distanceUnit"] as? String { ctx["distanceUnit"] = unit }

    if session.activationState != .activated {
      session.activate()
    }

    do {
      try session.updateApplicationContext(ctx)
      // Also try a reachable-message push for immediate delivery.
      if session.isReachable {
        session.sendMessage(ctx, replyHandler: nil, errorHandler: nil)
      }
      resolve([
        "supported": true,
        "paired": session.isPaired,
        "watchAppInstalled": session.isWatchAppInstalled,
        "reachable": session.isReachable,
      ])
    } catch {
      reject("watch_bridge_error", error.localizedDescription, error)
    }
  }

  @objc func getWatchState(_ resolve: @escaping RCTPromiseResolveBlock,
                           rejecter reject: @escaping RCTPromiseRejectBlock) {
    guard let session = self.session else {
      resolve([
        "supported": false,
        "paired": false,
        "watchAppInstalled": false,
        "reachable": false,
      ])
      return
    }
    resolve([
      "supported": true,
      "paired": session.isPaired,
      "watchAppInstalled": session.isWatchAppInstalled,
      "reachable": session.isReachable,
      "activationState": session.activationState.rawValue,
    ])
  }

  @objc func clearAuth(_ resolve: @escaping RCTPromiseResolveBlock,
                       rejecter reject: @escaping RCTPromiseRejectBlock) {
    guard let session = self.session else {
      resolve(["ok": true])
      return
    }
    do {
      try session.updateApplicationContext([
        "token": "",
        "userId": 0,
      ])
      resolve(["ok": true])
    } catch {
      reject("watch_bridge_error", error.localizedDescription, error)
    }
  }

  // MARK: - WCSessionDelegate

  func session(_ session: WCSession,
               activationDidCompleteWith activationState: WCSessionActivationState,
               error: Error?) { /* no-op */ }

  func sessionDidBecomeInactive(_ session: WCSession) { }

  func sessionDidDeactivate(_ session: WCSession) {
    // Required — reactivate for switching watches.
    session.activate()
  }

  func session(_ session: WCSession, didReceiveMessage message: [String : Any]) {
    // The watch tells us it completed a run; emit via NotificationCenter so
    // JS side can listen if needed in the future.
    if let kind = message["kind"] as? String, kind == "watch.run.completed" {
      NotificationCenter.default.post(
        name: Notification.Name("PaceUpWatchRunCompleted"),
        object: nil,
        userInfo: message
      )
    }
  }

  func session(_ session: WCSession,
               didReceiveApplicationContext applicationContext: [String : Any]) {
    if let kind = applicationContext["kind"] as? String, kind == "watch.run.completed" {
      NotificationCenter.default.post(
        name: Notification.Name("PaceUpWatchRunCompleted"),
        object: nil,
        userInfo: applicationContext
      )
    }
  }
}
`;

function withPaceUpWatchBridge(config) {
  // Write Swift + ObjC files into ios/
  config = withDangerousMod(config, [
    "ios",
    (cfg) => {
      const iosRoot = cfg.modRequest.platformProjectRoot;
      fs.writeFileSync(path.join(iosRoot, "PaceUpWatchBridge.m"), BRIDGE_M, "utf8");
      fs.writeFileSync(path.join(iosRoot, "PaceUpWatchBridge.swift"), BRIDGE_SWIFT, "utf8");
      return cfg;
    },
  ]);

  // Register in Xcode project against the main app target.
  //
  // Uses the same low-level access patterns as with-paceup-widget-extension.js
  // because xcode@3.0.1 (currently in node_modules) does not expose
  // .pbxGroupSection() or .pbxNativeTargetSection() as methods — you reach
  // into project.hash.project.objects directly.
  config = withXcodeProject(config, (cfg) => {
    const project = cfg.modResults;
    const projectName = cfg.modRequest.projectName || "PaceUp";

    // Find main target UUID.
    const nativeTargets =
      project.hash.project.objects["PBXNativeTarget"] || {};
    let mainTargetUUID = null;
    for (const k of Object.keys(nativeTargets)) {
      if (k.endsWith("_comment")) continue;
      const t = nativeTargets[k];
      if (!t || !t.name) continue;
      const n = String(t.name).replace(/"/g, "");
      if (n === projectName) {
        mainTargetUUID = k;
        break;
      }
    }
    if (!mainTargetUUID) return cfg;

    // Find main group UUID (the group whose name matches the project).
    const pbxGroups = project.hash.project.objects["PBXGroup"] || {};
    let mainGroupUUID = null;
    for (const k of Object.keys(pbxGroups)) {
      if (k.endsWith("_comment")) continue;
      const g = pbxGroups[k];
      if (!g) continue;
      const name = String(g.name || g.path || "").replace(/"/g, "");
      if (name === projectName) {
        mainGroupUUID = k;
        break;
      }
    }
    if (!mainGroupUUID) return cfg;

    // Avoid duplicate registration across re-runs.
    if (project.hasFile && project.hasFile("PaceUpWatchBridge.swift")) {
      return cfg;
    }

    project.addSourceFile(
      "PaceUpWatchBridge.m",
      { target: mainTargetUUID },
      mainGroupUUID
    );
    project.addSourceFile(
      "PaceUpWatchBridge.swift",
      { target: mainTargetUUID },
      mainGroupUUID
    );

    return cfg;
  });

  return config;
}

module.exports = withPaceUpWatchBridge;
